@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    """Manual processing endpoint with authentication"""
    try:
        # Security: Validate request
        if not req.get_body():
            return func.HttpResponse("Request body required", status_code=400)
        
        # Security: Parse with size limit
        body = req.get_json()
        
        # Security: Validate required fields
        if 'blob_name' not in body:
            return func.HttpResponse("blob_name required", status_code=400)
        
        blob_name = body['blob_name']
        
        # Security: Validate blob path
        if not validate_blob_path(blob_name):
            return func.HttpResponse("Invalid blob path", status_code=403)
        
        # Security: Sanitize blob name
        sanitized_name = sanitize_filename(os.path.basename(blob_name))
        
        # Process blob
        blob_service_client = BlobServiceClient(STORAGE_ACCOUNT_URL, credential=credential)
        
        # Security: Extract container and blob path safely
        parts = blob_name.split('/', 1)
        if len(parts) != 2:
            return func.HttpResponse("Invalid blob path format", status_code=400)
        
        container_name, blob_path = parts
        
        # Security: Validate container
        if ALLOWED_BLOB_CONTAINERS and ALLOWED_BLOB_CONTAINERS[0]:
            if container_name not in ALLOWED_BLOB_CONTAINERS:
                return func.HttpResponse("Container not allowed", status_code=403)
        
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_path)
        
        # Security: Check blob exists and get properties
        properties = blob_client.get_blob_properties()
        
        # Security: Validate size before download
        if not validate_file_size(properties.size):
            return func.HttpResponse(f"File too large (max {MAX_FILE_SIZE_MB}MB)", status_code=413)
        
        # Download and process
        content = blob_client.download_blob().readall()
        result = process_file_content(content, sanitized_name)
        
        return func.HttpResponse(
            json.dumps(result),
            mimetype="application/json",
            status_code=200
        )
        
    except ValueError as ve:
        return func.HttpResponse(str(ve), status_code=400)
    except Exception as e:
        logging.error(f"Error in manual process: {str(e)}")
        return func.HttpResponse("Internal server error", status_code=500)